using namespace std;

long long solve(std::string s) {
    int n = s.length();

    // We are looking for the smallest index i such that s[i] == s[n - i - 1].
    // We iterate i starting from 0 up to the middle of the string (inclusive of the middle for odd length).

    // The condition i <= n - i - 1 simplifies to 2*i <= n - 1, or i <= (n - 1) / 2.
    // Since we want the *smallest* such i, we iterate i from 0 upwards.

    // If we iterate i from 0 up to n/2 (exclusive for strict pairs, but the loop structure handles it),
    // we cover all potential candidates for the smallest i.

    for (int i = 0; i < n; ++i) {
        int j = n - 1 - i;

        // Since we are looking for the *smallest* i, we must check i in increasing order.
        // The iteration `for (int i = 0; i < n; ++i)` is correct for finding the smallest i.

        // We only need to check pairs (i, j) where i <= j to avoid redundant checks, 
        // but since the problem asks for the smallest *i*, checking all i from 0 up to n-1 is fine,
        // as the first match found will be the smallest.

        // However, notice that if i > n - i - 1 (i.e., i > j), then j < i. 
        // If s[i] == s[j] is true, then the pair (j, i) would have already been checked 
        // when the loop index was j, and since j < i, that earlier index j would have been a smaller valid answer.
        // Therefore, we only need to check up to the midpoint, i <= n - i - 1.

        if (i > j) {
            // We have passed the midpoint, any subsequent i will be larger than j, 
            // and if a match exists, it would have been found earlier.
            break;
        }

        if (s[i] == s[j]) {
            return i;
        }
    }

    return -1;
}
